import { useEffect, useState, useRef } from 'react';
import Loader from 'react-loaders';
import { Link } from 'react-router-dom';
import AnimatedLetters from '../AnimatedLetters';
import './index.scss';
import bgImage from '../../assets/images/oldTraffordBackground.jpg';

const Home = () => {
    const [letterClass, setLetterClass] = useState('text-animate');
    const nameArray = "Welcome to".split("");
    const jobArray = "EPL".split("");
    const playerRef = useRef(null);
    const [isMuted, setIsMuted] = useState(true);

    useEffect(() => {
        const timerId = setTimeout(() => {
            setLetterClass('text-animate-hover');
        }, 4000);
        return () => clearTimeout(timerId);
    }, []);

    useEffect(() => {
        const tag = document.createElement('script');
        tag.src = "https://www.youtube.com/iframe_api";
        const firstScriptTag = document.getElementsByTagName('script')[0];
        firstScriptTag.parentNode.insertBefore(tag, firstScriptTag);

        window.onYouTubeIframeAPIReady = () => {
            playerRef.current = new window.YT.Player('bottom-right-video', {
                events: {
                    'onReady': onPlayerReady,
                }
            });
        };

        return () => {
            delete window.onYouTubeIframeAPIReady;
            if (playerRef.current?.destroy) playerRef.current.destroy();
        };
    }, []);

    const onPlayerReady = (event) => {
        event.target.playVideo();
    };

    const toggleMute = () => {
        if (!playerRef.current) return;
        if (isMuted) {
            playerRef.current.unMute();
            setIsMuted(false);
        } else {
            playerRef.current.mute();
            setIsMuted(true);
        }
    };

    return (
        <div
            className="home-page"
            style={{
                backgroundImage: `url(${bgImage})`,
                backgroundSize: 'cover',
                backgroundPosition: 'center',
                backgroundRepeat: 'no-repeat',
                width: '100%',
                height: '100vh',
                position: 'relative',
            }}
        >
            {/* 🔳 Dark overlay to increase text visibility */}
            <div className="overlay"></div>

            <div className="container">
                <div className="text-zone">
                    <h1>
                        <img
                            src="EPLOGO.png"
                            alt="EPL Logo"
                        />
                        <br />
                        <AnimatedLetters letterClass={letterClass} strArray={nameArray} idx={12} />
                        <br />
                        <AnimatedLetters letterClass={letterClass} strArray={jobArray} idx={15} />
                    </h1>
                    <h2>Your home For The Future Of EPL Coverage !</h2>
                    <Link to="/teams" className="flat-button">GET STARTED</Link>
                </div>
            </div>

            {/* ✅ Bottom-right video and button */}
            <div className="video-container">
                <iframe
                    id="bottom-right-video"
                    src="https://www.youtube.com/embed/wz1r_VJaJZw?autoplay=1&mute=1&loop=1&playlist=wz1r_VJaJZw&enablejsapi=1"
                    frameBorder="0"
                    allow="autoplay; encrypted-media; picture-in-picture"
                    allowFullScreen
                    title="bottom right video"
                ></iframe>
                <button onClick={toggleMute} className="mute-button-video">
                    {isMuted ? '🔇 Sound On' : '🔊 Sound Off'}
                </button>
            </div>

            <Loader type="pacman" />
        </div>
    );
};

export default Home;
